import React, { useState } from "react";
import "../styles/MoNews.css";
import ReadMore from "./ReadMore";
import NewsCard from "./NewsCard";

const articles = [
  {
    id: 1,
    title: "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORT LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/news1.jpg",
    description: "The key to a successful criminal law enforcement depends on the evidence that has been...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 2,
    title: "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news2.jpg",
    description: "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 3,
    title: "Reformation of Indonesian Criminal Law: A Comparison of the Current Criminal Code (KUHP) and the New National Criminal Code (KUHP Nasional)",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description: "The current Criminal Code (KUHP) is also known as the Wetboek van Strafrecht...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 4,
    title: "Fixed-Term Employment Agreement Standards Following Constitutional Court Decision No. 168/PUU-XXI/2023",
    date: "06 February, 2025",
    image: "/images/news4.jpg",
    description: "A fixed-term employment agreement has a unique impact on labor regulations...",
    fullText: "Full article content goes here. This is the detailed explanation...",
  },
];

const MoreNews = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedArticle, setSelectedArticle] = useState(null);

  const openModal = (article) => {
    setSelectedArticle(article);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedArticle(null);
  };

  return (
    <div className="MoreNews">
      <h2>All News & Articles</h2>
      <div className="news-container">
        {articles.map((article) => (
          <NewsCard key={article.id} article={article} onReadMoreClick={openModal} />
        ))}
      </div>

      {isModalOpen && selectedArticle && (
        <ReadMore selectedArticle={selectedArticle} closeModal={closeModal} />
      )}
    </div>
  );
};

export default MoreNews;
